import { BaseLayerDataError } from './BaseLayerDataError.js';
import { DisabledState } from '../slots/states/DisabledState.js';

interface MapUnavailableProps {
  isFetchingFeatures: boolean;
  isDisabled: boolean;
  error: boolean;
  chartHeight: string | number;
}

export const MapUnavailable = ({
  chartHeight,
  error,
  isDisabled,
  isFetchingFeatures,
}: MapUnavailableProps) => {
  if (error) {
    return <BaseLayerDataError height={chartHeight} />;
  }
  if (!isFetchingFeatures && isDisabled) {
    return <DisabledState height={chartHeight} />;
  }
};

MapUnavailable.displayName = 'MapUnavailable';
